//添加
export function insertSysConfigApi(query) {
  return request({
    url: '/apiIP/sys-config/insert',
    method: 'post',
    data: query,
  })
}
//修改 
export function updateSysConfigApi(query) {
    return request({
        url: '/apiIP/sys-config/update',
        method: 'post',
        data: query,
    })
}
//查询
export function querySysConfigApi(query) {
    return request({
        url: '/apiIP/sys-config/query',
        method: 'post',
        data: query,
    })
}

//删除 分组
