<template>
  <LTPages
      :title="'系统项配置'"
      isNormal
  >
    <template  v-slot:content>
      <div class=" SystemConfig-Main">
        <div class="SystemConfig-Row">
          <span>系统名称</span>
          <span>
            <el-input v-model="SystemConfigForm['sysName']"></el-input>
          </span>
        </div>
        <div class="SystemConfig-Row">
          <span>企业名称</span>
          <span>
            <el-input v-model="SystemConfigForm['mineName']"></el-input>
          </span>
        </div>
        <div class="SystemConfig-Row">
          <span>企业ID</span>
          <span>
            <el-input v-model="SystemConfigForm['mineId']" @input="SystemConfigForm['mineId']=SystemConfigForm['mineId'].replace(/\D/g, '')"></el-input>
          </span>
        </div>

      </div>
      <div class=" SystemConfig-Btn" @click="setConfig">保存</div>
    </template>
  </LTPages>
</template>

<script>
import {queryDetailApi, setConfigApi} from "@/api/System/SystemConfig";
export default {
  name: "SystemConfig",
  data () {
    return {
      SystemConfigForm: {
        sysName:"",
        mineId:"",
        mineName:"",
      }
    }
  },
  created() {
    this.queryDetail()
  },
  methods: {
    //查询
    queryDetail() {
      queryDetailApi().then(res => {
        this.SystemConfigForm = res.data.result?res.data.result:{
          sysName:"",
          mineId:"",
          mineName:"",
        }
      })
    },
    //保存
    setConfig() {
      setConfigApi(this.SystemConfigForm).then(res => {
        if(res.data.code != '2000') return this.$message.error({message:res.data.message,showClose:true,duration:1000});
        this.$message.success({message:res.data.message,showClose:true,duration:1000});
        //Bus.$emit('updateProjectName',this.SystemConfigForm.sysName);
        this.queryDetail();
      })
    }
    // END!=====================
  }
}
</script>

<style scoped lang="scss">
.SystemConfig-Main{
  width: 100%;
  height: calc(100% - 80px);
  margin: 15px auto;
  .SystemConfig-Row{
    width: calc(100% / 3);
    height: 32px;
    display: flex;
    justify-content: space-between;
    margin: 0 0 25px 0;
    align-items: center;
    span{
      &:nth-of-type(1){
        width: 100px;
        color:#ffffff;
        font-size: 15px;
        text-align: right;
      }
      &:nth-of-type(2){
        width: calc(100% - 110px);
      }
    }
    ::v-deep .el-input__inner {
      height: 40px;
      background: transparent ;
      border: 1px solid #95B2C4;
      //url("~@/packages/components/image/box-bg.png") no-repeat center center !important;
      //background-size: 100% 100% !important;
      color: #fff !important;
    }
  }
}
.SystemConfig-Btn{
  width: 100px;
  height: 50px;
  line-height: 50px;
  text-align: center;
  color:#fff;
  font-size: 15px;
  cursor: pointer;
  margin: 0 auto;
  background: url("~@/assets/image/new-search.png") no-repeat;
  background-size: 100% 100%;
}
</style>